import { Component } from '@angular/core';
import { NgFor, NgClass } from '@angular/common';

interface Project {
  title: string;
  stack: string;
  imageAlt: string;
}

interface Skill {
  name: string;
  short: string;
}

interface SocialLink {
  name: string;
  icon: string;
  href: string;
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [NgFor, NgClass],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
})
export class AppComponent {
  sections = ['home', 'about', 'projects', 'skills', 'contact'] as const;
  activeSection: (typeof this.sections)[number] = 'home';

  projects: Project[] = [
    {
      title: 'Plataforma de E-Commerce',
      stack: 'React, Node.js, MongoDB',
      imageAlt: 'Screenshot da plataforma de e-commerce',
    },
    {
      title: 'App de Gestão de Tarefas',
      stack: 'Vue.js, Express, MySQL',
      imageAlt: 'Screenshot do aplicativo de gestão de tarefas',
    },
    {
      title: 'Dashboard de Redes Sociais',
      stack: 'Next.js, Tailwind CSS',
      imageAlt: 'Screenshot do dashboard de redes sociais',
    },
  ];

  frontendSkills: Skill[] = [
    { name: 'HTML5', short: 'HTML' },
    { name: 'CSS3', short: 'CSS' },
    { name: 'JavaScript', short: 'JS' },
    { name: 'TypeScript', short: 'TS' },
    { name: 'Angular', short: 'NG' },
  ];

  toolSkills: Skill[] = [
    { name: 'Git', short: 'G' },
    { name: 'GitHub', short: 'GH' },
    { name: 'CI/CD', short: 'CI' },
    { name: 'Cloud', short: 'CL' },
  ];

  socialLinks: SocialLink[] = [
    { name: 'GitHub', icon: 'github', href: '#' },
    { name: 'LinkedIn', icon: 'linkedin', href: '#' },
    { name: 'Twitter', icon: 'twitter', href: '#' },
    { name: 'Telegram', icon: 'telegram', href: '#' },
  ];

  setActive(section: (typeof this.sections)[number]): void {
    this.activeSection = section;
    const target = document.getElementById(section);
    if (target) {
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }
}
